        7: '<div style="padding:20px;background:linear-gradient(135deg,#ffecd2,#fcb69f);border-radius:12px"><h3>🎨 Formatação Condicional</h3><div style="background:white;padding:20px;border-radius:8px"><p style="margin-bottom:15px"><strong>Formatação Condicional</strong> aplica cores/estilos automaticamente com base nos valores:</p><div style="display:grid;grid-template-columns:repeat(5,1fr);gap:5px;margin:20px 0"><div style="padding:15px;background:#C8E6C9;text-align:center;border-radius:4px;font-weight:bold">90</div><div style="padding:15px;background:#C8E6C9;text-align:center;border-radius:4px;font-weight:bold">85</div><div style="padding:15px;background:#FFF59D;text-align:center;border-radius:4px;font-weight:bold">70</div><div style="padding:15px;background:#FFAB91;text-align:center;border-radius:4px;font-weight:bold">45</div><div style="padding:15px;background:#EF9A9A;text-align:center;border-radius:4px;font-weight:bold">30</div></div><div style="padding:12px;background:#E8F5E9;border-left:4px solid #4CAF50;border-radius:4px"><strong>✅ Exemplo:</strong> Células com valores <70 ficam em vermelho automaticamente</div></div></div>',
        8: '<div style="padding:20px;background:linear-gradient(135deg,#667eea,#764ba2);border-radius:12px;color:white"><h3>➕ Função SUBTOTAL</h3><div style="background:white;padding:20px;border-radius:8px;color:#333"><p><strong>SUBTOTAL</strong> é especial porque <strong>ignora linhas ocultas por filtros</strong>:</p><div style="margin:20px 0;padding:15px;background:#E3F2FD;border-radius:4px"><code style="font-size:14px">=SUBTOTAL(9, A2:A100)</code><br><span style="font-size:13px;color:#666;margin-top:5px;display:block">9 = função SOMA<br>Ignora linhas filtradas/ocultas</span></div><div style="padding:12px;background:#FFF3CD;border-left:4px solid #FFA000;border-radius:4px"><strong>💡 Quando usar:</strong> Totais em tabelas com filtros ativos</div></div></div>',
        9: '<div style="padding:20px;background:linear-gradient(135deg,#f093fb,#f5576c);border-radius:12px;color:white"><h3>🔒 Validação de Dados</h3><div style="background:white;padding:20px;border-radius:8px;color:#333"><p style="margin-bottom:15px"><strong>Filtro Automático</strong> permite mostrar apenas linhas que atendem critérios:</p><div style="display:inline-block;padding:15px;background:#f5f5f5;border-radius:4px;margin:10px 0"><div style="padding:8px;background:#2196F3;color:white;border-radius:4px;margin-bottom:5px;cursor:pointer">Nome ▼</div><label style="display:block;margin:5px 0;cursor:pointer"><input type="checkbox" checked> Ana</label><label style="display:block;margin:5px 0;cursor:pointer"><input type="checkbox" checked> Bruno</label><label style="display:block;margin:5px 0;cursor:pointer"><input type="checkbox"> Carla</label></div><div style="padding:12px;background:#E3F2FD;border-left:4px solid #2196F3;border-radius:4px;margin-top:15px"><strong>✅ Atalho:</strong> <kbd>Ctrl + Shift + L</kbd></div></div></div>',
